// getClusterProxyConfig reads the cluster-wide Proxy settings from the informer
// cache when the config.openshift.io/v1 Proxy API is available. Returns nil when
// the API is not served (non-OpenShift cluster).
func (r *Reconciler) getClusterProxyConfig() *configv1.Proxy {
	if r.proxyInformers == nil || !r.proxyInformers.Applicable() {
		return nil
	}
	proxy, err := (*r.proxyInformers.InformerFactory).Config().V1().Proxies().Lister().Get("cluster")
	if err != nil {
		r.log.V(2).Info("unable to retrieve cluster proxy config, skipping proxy settings", "error", err)
		return nil
	}
	return proxy
}
